const items = $input.all();

// 1. Verificar si es IP privada
const ip = items[0].json.source_ip || '0.0.0.0';
const isPrivateIP = ip.startsWith('10.') || 
                   ip.startsWith('192.168.') || 
                   (ip.startsWith('172.') && parseInt(ip.split('.')[1]) >= 16 && parseInt(ip.split('.')[1]) <= 31);

// 2. Base de datos SIMULADA de threat intelligence
const threatDB = {
  '192.168.1.50': { 
    reputation: 'malicious', 
    tags: ['sql_injection', 'web_attack'],
    confidence: 0.85
  },
  '10.0.0.10': { 
    reputation: 'suspicious', 
    tags: ['port_scan'],
    confidence: 0.65
  }
};

// 3. Aplicar enriquecimiento
items[0].json.threat_intel = {
  is_private_ip: isPrivateIP,
  threat_info: threatDB[ip] || { 
    reputation: 'unknown', 
    tags: [], 
    confidence: 0 
  },
  geo_info: {
    country: isPrivateIP ? 'INTERNAL' : 'UNKNOWN',
    asn: 'N/A'
  },
  enrichment_timestamp: new Date().toISOString()
};

// 4. Calcular risk_score mejorado
let riskScore = 0;

// Base por severity
switch(items[0].json.severity) {
  case 'critical': riskScore = 90; break;
  case 'high': riskScore = 70; break;
  case 'medium': riskScore = 50; break;
  default: riskScore = 30;
}

// Bonificación por threat intelligence
if (items[0].json.threat_intel.threat_info.reputation === 'malicious') {
  riskScore += 20;
} else if (items[0].json.threat_intel.threat_info.reputation === 'suspicious') {
  riskScore += 10;
}

// Bonificación por múltiples eventos
if (items[0].json.event_count && items[0].json.event_count > 3) {
  riskScore += 15;
}

items[0].json.risk_score = Math.min(100, riskScore);
items[0].json.risk_level = riskScore >= 80 ? 'CRITICAL' : 
                          riskScore >= 60 ? 'HIGH' : 
                          riskScore >= 40 ? 'MEDIUM' : 'LOW';

return items;

// Nodo: Activar Workflows 4 y 5
const items = $input.all();
const results = [];

for (const item of items) {
  const alert = item.json;

  // Solo activar para alertas de alta severidad con IP válida
  if ((alert.severity === 'high' || alert.severity === 'critical') && 
      alert.source_ip && 
      alert.source_ip !== '0.0.0.0') {

    try {
      // Datos para auto-bloqueo (workflow 4)
      const blockData = {
        source_ip: alert.source_ip,
        threat_score: alert.risk_score || 75,
        severity: alert.severity,
        rule_name: alert.rule_name || 'Unknown',
        timestamp: new Date().toISOString(),
        reason: `Auto-bloqueo por: ${alert.rule_name || 'Alerta de seguridad'}`
      };

      // Datos para tickets (workflow 5)
      const ticketData = {
        title: `[${alert.severity.toUpperCase()}] ${alert.rule_name || 'Security Alert'}`,
        description: alert.description || `Alerta de seguridad desde ${alert.source_ip}`,
        severity: alert.severity,
        source_ip: alert.source_ip,
        category: alert.category || 'general',
        rule_name: alert.rule_name || 'Unknown',
        risk_score: alert.risk_score || 75
      };

      // Enviar a ambos webhooks (DENTRO del contenedor Docker)
      const responses = await Promise.allSettled([
        $http.post({
          url: 'http://n8n:5678/webhook/auto-block',
          body: blockData,
          headers: { 'Content-Type': 'application/json' },
          timeout: 3000
        }),
        $http.post({
          url: 'http://n8n:5678/webhook/create-ticket',
          body: ticketData,
          headers: { 'Content-Type': 'application/json' },
          timeout: 3000
        })
      ]);

      results.push({
        json: {
          ...alert,
          workflows_triggered: true,
          block_success: responses[0].status === 'fulfilled',
          ticket_success: responses[1].status === 'fulfilled',
          block_response: responses[0].status === 'fulfilled' ? responses[0].value.status : 'error',
          ticket_response: responses[1].status === 'fulfilled' ? responses[1].value.status : 'error'
        }
      });

    } catch (error) {
      results.push({
        json: {
          ...alert,
          workflows_triggered: false,
          error: error.message
        }
      });
    }
  } else {
    // Si no cumple criterios, pasar sin cambios
    results.push({ json: alert });
  }
}

return results;
